pipeline {
    agent any

    environment {
        REGISTRY = "my-private-registry.io"
        IMAGE_NAME = "sample-app"
        GITOPS_REPO = "git@github.com:org/gitops-repo.git"
        COVERAGE_THRESHOLD = "80"
    }

    tools {
        maven 'Maven-3.8.8'
    }

    stages {
        stage('Checkout') {
            steps {
                git branch: 'main',credentialsId: 'github-creds', url: 'https://github.com/manikantatarun/mvn-app.git'
            }
        }

        stage('Build & Unit Test') {
            steps {
                        sh 'mvn clean verify -Dmaven.test.failure.ignore=false'
            }
            post {
                always {
                    junit '**/target/surefire-reports/*.xml'
                }
            }
        }

        stage('Coverage Analysis') {
            steps {
                recordCoverage(
                    tools: [[parser: 'JACOCO', pattern: '**/target/site/jacoco/jacoco.xml']],
                    id: 'jacoco',
                    name: 'JaCoCo Coverage',
                    sourceCodeRetention: 'EVERY_BUILD',
                    qualityGates: [
                        [threshold: 80.0, metric: 'LINE', baseline: 'PROJECT', unstable: true],
                        [threshold: 70.0, metric: 'BRANCH', baseline: 'PROJECT', unstable: true]
                    ]
                )
            }
        }

        stage('SonarQube Analysis') {
            steps {
                timeout(time: 60, unit: 'SECONDS') {
                    withSonarQubeEnv('sonar-qube-server') {
                        sh '''
                            $SONAR_SCANNER_HOME/bin/sonar-scanner \
                            -Dsonar.projectKey=Solar-System-Project \
                            -Dsonar.sources=app.js \
                            -Dsonar.javascript.lcov.reportPaths=./coverage/lcov.info
                        '''
                    }
                }
                waitForQualityGate abortPipeline: true
            }
        }

        stage('Quality Gate') {
            steps {
                script {
                    def qg = waitForQualityGate()
                    if (qg.status != 'OK') {
                        error "Pipeline aborted due to Quality Gate failure: ${qg.status}"
                    }
                }
            }
        }

        stage('Security Scans') {
            parallel {
                stage('Trivy FS Scan') {
                    steps {
                        sh 'trivy fs . || true'
                    }
                }
                stage('Dependency Scan') {
                    steps {
                        sh 'mvn org.owasp:dependency-check-maven:check'
                        dependencyCheckPublisher pattern: '**/dependency-check-report.xml'
                    }
                }
            }
        }

        stage('Docker Build & Push') {
            steps {
                script {
                    docker.withRegistry("https://${REGISTRY}", "${DOCKER_CRED}") {
                        def image = docker.build("${REGISTRY}/${IMAGE_NAME}:${env.BUILD_NUMBER}")
                        image.push()
                        image.push("latest")
                    }
                }
            }
        }

        stage('GitOps Update') {
            steps {
                sshagent(['github-ssh']) {
                    sh '''
                        git config user.email "ci@mycompany.com"
                        git config user.name "ci-bot"
                        git clone git@github.com:myorg/gitops-config.git
                        cd gitops-config/environments/dev
                        yq e -i '.spec.template.spec.containers[0].image = "${REGISTRY}/${IMAGE_NAME}:${BUILD_NUMBER}"' deployment.yaml
                        git add .
                        git commit -m "Update ${IMAGE_NAME} image to ${BUILD_NUMBER}"
                        git push origin main
                    '''
                }
            }
        }

        stage('Approval for Staging') {
            steps {
                input message: 'Promote to Staging?', ok: 'Deploy'
            }
        }

        stage('Deploy to Staging') {
            steps {
                sshagent(['github-ssh']) {
                    sh '''
                        cd gitops-config/environments/staging
                        yq e -i '.spec.template.spec.containers[0].image = "${REGISTRY}/${IMAGE_NAME}:${BUILD_NUMBER}"' deployment.yaml
                        git add .
                        git commit -m "Promote ${IMAGE_NAME}:${BUILD_NUMBER} to Staging"
                        git push origin main
                    '''
                }
            }
        }

        stage('Approval for Production') {
            steps {
                input message: 'Promote to Production?', ok: 'Deploy'
            }
        }

        stage('Deploy to Production') {
            steps {
                sshagent(['github-ssh']) {
                    sh '''
                        cd gitops-config/environments/prod
                        yq e -i '.spec.template.spec.containers[0].image = "${REGISTRY}/${IMAGE_NAME}:${BUILD_NUMBER}"' deployment.yaml
                        git add .
                        git commit -m "Promote ${IMAGE_NAME}:${BUILD_NUMBER} to Production"
                        git push origin main
                    '''
                }
            }
        }
    }

    post {
        success {
            echo "Pipeline completed successfully ✅"
        }
        failure {
            echo "Pipeline failed ❌"
        }
    }
}
